INSERT INTO questions (section, type, content, correct_answer, cefr_level, difficulty, competency_tag, aircraft_context, role_tag, active, is_latest, version_number) VALUES
-- Grammar (general)
('grammar','multiple_choice','All passengers _____ fasten their seatbelts during takeoff and landing.\nA) must\nB) can\nC) might\nD) would','A','A2','easy','structural_accuracy','general','general',true,true,1),
('grammar','multiple_choice','The flight _____ delayed due to severe weather conditions.\nA) is\nB) was\nC) were\nD) been','B','A2','easy','tense_usage','general','general',true,true,1),
('grammar','multiple_choice','If the weather _____ worse, we will divert to an alternate airport.\nA) gets\nB) will get\nC) got\nD) has gotten','A','B1','medium','conditional_forms','general','general',true,true,1),
('grammar','multiple_choice','The safety demonstration _____ before every departure.\nA) is performed\nB) performs\nC) performing\nD) was perform','A','A2','easy','passive_voice','general','general',true,true,1),
('grammar','multiple_choice','Neither the captain _____ the first officer reported any anomalies.\nA) or\nB) and\nC) nor\nD) but','C','B1','medium','structural_accuracy','general','general',true,true,1),
('grammar','multiple_choice','Emergency exits are located _____ both sides of the aircraft.\nA) in\nB) on\nC) at\nD) by','B','A2','easy','phraseology_grammar','general','general',true,true,1),
('grammar','multiple_choice','The crew _____ been briefed on the new security procedures.\nA) has\nB) have\nC) is\nD) was','B','B1','medium','tense_usage','general','general',true,true,1),
('grammar','fill_blank','Complete the sentence: The aircraft was inspected _____ (thorough) before the flight.','thoroughly','B1','medium','structural_accuracy','general','general',true,true,1),
('grammar','fill_blank','Complete the sentence: Safety is _____ (important) than schedule in aviation.','more important','A2','easy','structural_accuracy','general','general',true,true,1),
('grammar','multiple_choice','By the time we landed, the ground crew _____ the gate ready.\nA) had made\nB) has made\nC) made\nD) making','A','B2','medium','tense_usage','general','general',true,true,1),
('grammar','multiple_choice','The report _____ submitted by the end of the shift.\nA) must be\nB) must\nC) must to be\nD) must being','A','B1','medium','passive_voice','general','general',true,true,1),
('grammar','fill_blank','Complete the sentence: He asked _____ (polite) if there were any seats available.','politely','A2','easy','structural_accuracy','general','general',true,true,1),
('grammar','multiple_choice','_____ the delay, all passengers remained calm.\nA) Despite\nB) Although\nC) However\nD) Because','A','B1','medium','structural_accuracy','general','general',true,true,1),
('grammar','multiple_choice','The new regulation requires that all staff _____ additional training.\nA) complete\nB) completes\nC) completing\nD) to complete','A','B2','medium','structural_accuracy','general','general',true,true,1),
('grammar','multiple_choice','How _____ luggage are you carrying today?\nA) many\nB) much\nC) some\nD) few','B','A2','easy','structural_accuracy','general','general',true,true,1),

-- Reading (general)
('reading','multiple_choice','Read the following safety notice:\n\n"IMPORTANT: In the event of a cabin depressurization, oxygen masks will drop automatically from the panel above your seat. Pull the mask towards you, place it over your nose and mouth, and breathe normally. Secure your own mask before assisting others."\n\nWhat should you do FIRST when oxygen masks drop?\nA) Help the person next to you\nB) Pull the mask towards you and put it on\nC) Call a flight attendant\nD) Move to the nearest exit','B','A2','easy','safety_card_reading','general','general',true,true,1),
('reading','multiple_choice','Read the NOTAM:\n\n"NOTAM B0412/26 — ILS RWY 05 unserviceable from 20 MAR to 22 MAR 2026. VOR/DME approach available. Contact tower on 118.1 for updated approach information."\n\nWhich approach system is NOT working?\nA) VOR/DME\nB) ILS for Runway 05\nC) Tower communications\nD) All approach systems','B','B1','medium','notam_interpretation','general','general',true,true,1),
('reading','multiple_choice','Read the weather report:\n\n"METAR LTBA 180900Z 33012KT 9999 FEW040 SCT100 18/08 Q1015 NOSIG"\n\nWhat is the visibility at this airport?\nA) 3300 metres\nB) 9999 metres (10km or more)\nC) 1800 metres\nD) 4000 metres','B','B2','hard','weather_report_reading','general','general',true,true,1),
('reading','multiple_choice','Read the regulation excerpt:\n\n"All aviation personnel must report any incident, no matter how minor, within 24 hours using the Safety Reporting System. Failure to report may result in disciplinary action. All reports are treated confidentially."\n\nWithin what timeframe must incidents be reported?\nA) Immediately\nB) Within 24 hours\nC) Within 48 hours\nD) By end of the week','B','A2','easy','sop_comprehension','general','general',true,true,1),
('reading','multiple_choice','Read the memo:\n\n"Due to runway construction at Gate B, all departures between 0600-1400 local will use Taxiway Charlie instead of Taxiway Alpha. Ground crews must verify routing with ATC before each pushback. This change is effective from 19 March to 5 April 2026."\n\nWhen does this routing change end?\nA) 19 March 2026\nB) 5 April 2026\nC) When construction is done\nD) After 1400 local','B','B1','medium','sop_comprehension','general','general',true,true,1),

-- Writing (general)
('writing','written_response','Write a short email (at least 50 words) to your colleague explaining that tomorrow''s morning briefing has been moved from 0800 to 0900 due to a schedule change. Include the reason and ask them to confirm they received the message.','Model: Subject: Briefing Time Change. Hi [Name], I am writing to let you know that tomorrow morning briefing has been rescheduled from 0800 to 0900. This change is due to an updated shift rotation schedule from management. Please arrive at the briefing room by 0855. Could you please confirm that you have received this message? Thank you.','A2','easy','operational_message','general','general',true,true,1),
('writing','written_response','You witnessed an unsafe situation at work — a vehicle was driving too fast on the airport ramp near aircraft. Write a safety report (at least 60 words) describing what you saw, when and where it happened, and what action should be taken.','Model: Safety Incident Report. Date: 18 March 2026, Time: 1430 local. Location: Ramp area near Gate 7. I observed a baggage tractor driving at excessive speed approximately 40 km/h in the aircraft movement area near Stand 7B. The vehicle passed within 3 metres of parked aircraft TC-FLY without slowing down. No ground personnel were wearing high-visibility vests in the area. I recommend reviewing CCTV footage, identifying the driver, and conducting a ramp safety refresher for all ground vehicle operators.','B1','medium','safety_report','general','general',true,true,1),
('writing','written_response','A passenger has complained that their special meal was not loaded on the flight. Write a professional response letter (at least 60 words) apologizing and explaining what steps will be taken to prevent this in the future.','Model answer should include apology, acknowledgment, explanation of corrective action, and offer of goodwill gesture.','B1','medium','passenger_complaint','general','general',true,true,1),
('writing','written_response','Write a brief handover note (at least 50 words) for the next shift, summarizing what was completed during your shift, what tasks are still pending, and any important information they need to know.','Model answer should include completed tasks, pending items, and critical notes for next shift.','A2','easy','operational_message','general','general',true,true,1),
('writing','written_response','Your team needs to work overtime this weekend due to increased flight schedules. Write an email (at least 60 words) to your team members informing them about the overtime, the reason, and the compensation they will receive.','Model answer should include clear information about overtime schedule, reason, and compensation details.','B2','medium','operational_message','general','general',true,true,1),

-- Speaking (general)
('speaking','audio_response','Introduce yourself as if you are at a job interview for an aviation position. Include your name, your experience, why you chose aviation, and what skills you bring to the role.\n\nSpeak for at least 45 seconds.','Expected: Clear introduction, relevant experience mention, motivation for aviation, key skills. Professional tone.','B1','medium','oral_briefing','general','general',true,true,1),
('speaking','audio_response','Describe what you would do if you noticed a fire in your work area at the airport. Explain the steps you would take in order.\n\nSpeak for at least 30 seconds.','Expected: Alert others, activate alarm, use fire extinguisher if safe, evacuate, call emergency services. Clear sequence.','A2','easy','roleplay_emergency','general','general',true,true,1),
('speaking','audio_response','Your colleague is new and asks you: "What are the most important safety rules at the airport?" Explain at least 4 safety rules.\n\nSpeak for at least 40 seconds.','Expected: PPE requirements, FOD awareness, vehicle safety, restricted areas, emergency procedures, communication protocols.','B1','medium','ground_communication','general','general',true,true,1),
('speaking','audio_response','Describe the weather conditions you can see outside right now. Then explain how bad weather can affect airport operations.\n\nSpeak for at least 30 seconds.','Expected: Description of current weather, impact on visibility, delays, de-icing needs, wind effects on landing/takeoff.','A2','easy','oral_briefing','general','general',true,true,1),
('speaking','audio_response','You need to make an announcement to passengers about a 45-minute flight delay. Deliver the announcement professionally, including the reason (technical check) and what the airline will provide (refreshments).\n\nSpeak for at least 30 seconds.','Expected: Professional tone, clear information, empathy, solution offered.','B2','medium','cabin_announcement','general','general',true,true,1),

-- Listening (general)
('listening','multiple_choice','[AUDIO] "Attention all staff. This is a reminder that the mandatory fire safety drill will take place tomorrow at 1400 hours in the main hangar. All personnel must attend. Please wear your safety equipment. The drill will last approximately 30 minutes."\n\nWhen is the fire drill?\nA) Today at 1400\nB) Tomorrow at 1400\nC) Tomorrow at 1300\nD) Next week','B','A2','easy','emergency_broadcast','general','general',true,true,1),
('listening','multiple_choice','[AUDIO] "Good morning. Due to fog, visibility is currently 400 metres. All ground operations are suspended until visibility improves to at least 550 metres. Stand by for further updates on frequency 121.9."\n\nWhat is the current visibility?\nA) 550 metres\nB) 400 metres\nC) 121 metres\nD) 900 metres','B','B1','medium','ground_ops_radio','general','general',true,true,1),
('listening','multiple_choice','[AUDIO] "All personnel, be advised that Taxiway Delta is closed for maintenance between intersection D2 and D5. Use Taxiway Echo as an alternative. This closure will remain in effect until further notice."\n\nWhich alternative taxiway should be used?\nA) Taxiway Delta\nB) Taxiway Bravo\nC) Taxiway Echo\nD) Taxiway Alpha','C','A2','easy','ground_ops_radio','general','general',true,true,1),
('listening','multiple_choice','[AUDIO] "Tower, this is Turkish 1842 requesting pushback from Gate 12. We have information Bravo, ready to copy taxi instructions."\n\nWhat is the aircraft requesting?\nA) Landing clearance\nB) Pushback from Gate 12\nC) Runway change\nD) Fuel request','B','B1','medium','atc_phraseology','general','general',true,true,1),
('listening','multiple_choice','[AUDIO] "Maintenance Control, this is Line Station 3. We have completed the daily inspection on aircraft TC-SKY. All items satisfactory except the left nose wheel tire which shows 2mm tread remaining. Minimum is 3mm. Requesting tire change before next departure."\n\nWhat problem was found?\nA) Engine oil is low\nB) Left nose wheel tire tread is below minimum\nC) The brakes need changing\nD) The inspection was not completed','B','B1','medium','ground_ops_radio','general','general',true,true,1),
('listening','multiple_choice','[AUDIO] "Ladies and gentlemen, the captain has turned on the fasten seatbelt sign. We are expecting some turbulence ahead. Please return to your seats and keep your seatbelts fastened until the sign is turned off. Cabin crew, please be seated."\n\nWhy was the seatbelt sign turned on?\nA) The plane is landing\nB) Turbulence is expected\nC) The plane is taking off\nD) There is an emergency','B','A2','easy','cabin_announcement','general','general',true,true,1),
('listening','multiple_choice','[AUDIO] "Ground, Pegasus 247 Heavy. We need to return to the gate. We have a medical emergency on board. Requesting priority handling and an ambulance at Gate 8."\n\nWhat type of emergency is reported?\nA) Engine failure\nB) Medical emergency\nC) Fire on board\nD) Fuel leak','B','B1','medium','emergency_broadcast','general','general',true,true,1),
('listening','multiple_choice','[AUDIO] "Attention ground crew. Aircraft at Stand 14 will be departing in 20 minutes. Please ensure all ground equipment is removed and the area is clear. Headset operator, confirm ready for pushback."\n\nHow soon will the aircraft depart?\nA) In 10 minutes\nB) In 20 minutes\nC) In 30 minutes\nD) Immediately','B','A2','easy','ground_ops_radio','general','general',true,true,1),
('listening','multiple_choice','[AUDIO] "This is the operations manager speaking. I want to remind everyone that we have a VIP flight departing at 1600 today from Gate 1. All security protocols must be strictly followed. Additional screening is required for all personnel accessing the gate area."\n\nWhat special requirement is mentioned?\nA) No personnel allowed near Gate 1\nB) Additional security screening for personnel\nC) The flight is cancelled\nD) Gate 1 is closed','B','B1','medium','ground_ops_radio','general','general',true,true,1),
('listening','multiple_choice','[AUDIO] "Control tower, SunExpress 502. We have landed on Runway 36 and vacated via taxiway Alpha 3. Request taxi to Gate 22."\n\nWhat has the aircraft just done?\nA) Taken off\nB) Landed and left the runway\nC) Requested fuel\nD) Reported an emergency','B','B1','medium','atc_phraseology','general','general',true,true,1);


